import { Damage, Item, Policy } from "./types.js";

const DEDUCTIBLE = 100;
const HIGH_ENCH_PAYOUT_THRESHOLD = 8;
const HIGH_ENCH_PAYOUT_RATE = 0.5;

export function createPolicy(items: Item[], insuranceSum: number): Policy {
  const cap = insuranceSum * 2;
  return {
    items: items.slice(),
    insuranceSum,
    cap,
    remainingCap: cap,
  };
}

export function processClaim(
  policy: Policy,
  damages: Damage[],
): { payout: number; remainingCap: number } {
  // Validate: every damage must match an unused policy item of the same type.
  // Each policy item can be referenced at most once per claim.
  const matched: Item[] = [];
  const availableItems = policy.items.slice();
  for (const damage of damages) {
    if (damage.amount < 0) {
      throw new Error(`Negative damage amount: ${damage.amount}`);
    }
    const idx = availableItems.findIndex((it) => it.type === damage.itemType);
    if (idx === -1) {
      throw new Error(
        `Damage references item type "${damage.itemType}" not (or no longer) in policy`,
      );
    }
    matched.push(availableItems[idx]);
    availableItems.splice(idx, 1);
  }

  // Compute the gross payout per damage (before cap).
  let totalPayout = 0;
  for (let i = 0; i < damages.length; i++) {
    const damage = damages[i];
    const item = matched[i];
    let reimbursable = damage.amount;
    const isDragon = item.material === "dragon";
    const isHighEnch = typeof item.enchantment === "number" && item.enchantment >= HIGH_ENCH_PAYOUT_THRESHOLD;
    if (isHighEnch && !isDragon) {
      reimbursable = damage.amount * HIGH_ENCH_PAYOUT_RATE;
    }
    // Dragon material: full reimbursement (overrides high-enchantment reduction
    // unless BOTH apply, in which case the 50% rule wins per spec).
    if (isDragon && isHighEnch) {
      reimbursable = damage.amount * HIGH_ENCH_PAYOUT_RATE;
    }
    // Else dragon alone → full reimbursement (no reduction); already reimbursable=damage.amount.

    const afterDeductible = Math.max(0, reimbursable - DEDUCTIBLE);
    totalPayout += afterDeductible;
  }

  // Round payout down (MHPCO's favor).
  let payout = Math.floor(totalPayout);
  // Apply cap.
  if (payout > policy.remainingCap) {
    payout = policy.remainingCap;
  }
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
}

