import {
  ClaimStep,
  Policy,
  QuoteStep,
  Result,
  Scenario,
  ScenarioResult,
  Step,
} from "./types.js";
import { computePremium } from "./premium.js";
import { processClaim, createPolicy } from "./claim.js";
import { insuranceSum, isKnownType } from "./items.js";

export function runScenario(scenario: Scenario): ScenarioResult {
  const results: Result[] = [];
  const policies: Map<number, Policy> = new Map();
  let quoteCount = 0;

  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === "quote") {
      const quote = step as QuoteStep;
      for (const item of quote.items) {
        if (!isKnownType(item.type)) {
          throw new Error(`Unknown item type: ${item.type}`);
        }
      }
      const isFollowUp = quoteCount > 0;
      const premium = computePremium(scenario.customer, quote.items, isFollowUp);
      results.push({ premium });
      const sum = insuranceSum(quote.items);
      policies.set(i, createPolicy(quote.items, sum));
      quoteCount += 1;
    } else if (step.op === "claim") {
      const claim = step as ClaimStep;
      const policy = policies.get(claim.policy);
      if (!policy) {
        throw new Error(`Claim references unknown policy index: ${claim.policy}`);
      }
      for (const damage of claim.incident.damages) {
        if (!isKnownType(damage.itemType)) {
          throw new Error(`Unknown damage item type: ${damage.itemType}`);
        }
      }
      const { payout, remainingCap } = processClaim(policy, claim.incident.damages);
      results.push({ payout, remainingCap });
    } else {
      throw new Error(`Unknown op: ${(step as Step).op as string}`);
    }
  }

  return { results };
}

