import { Item } from "./types.js";

export interface ItemSpec {
  insuranceValue: number;
  basePremium: number;
  isComponent: boolean;
}

const MAIN_ITEMS: Record<string, ItemSpec> = {
  sword: { insuranceValue: 1000, basePremium: 100, isComponent: false },
  amulet: { insuranceValue: 600, basePremium: 60, isComponent: false },
  staff: { insuranceValue: 800, basePremium: 80, isComponent: false },
  potion: { insuranceValue: 400, basePremium: 40, isComponent: false },
};

const COMPONENT_ITEMS: Record<string, ItemSpec> = {
  rune: { insuranceValue: 250, basePremium: 25, isComponent: true },
  moonstone: { insuranceValue: 250, basePremium: 25, isComponent: true },
};

export function getItemSpec(type: string): ItemSpec | undefined {
  return MAIN_ITEMS[type] ?? COMPONENT_ITEMS[type];
}

export function isKnownType(type: string): boolean {
  return getItemSpec(type) !== undefined;
}

export function isComponent(type: string): boolean {
  return COMPONENT_ITEMS[type] !== undefined;
}

// Compute the policy's insurance sum (does not consider block discounts).
export function insuranceSum(items: Item[]): number {
  let sum = 0;
  for (const item of items) {
    const spec = getItemSpec(item.type);
    if (!spec) throw new Error(`Unknown item type: ${item.type}`);
    sum += spec.insuranceValue;
  }
  return sum;
}

// Compute the policy's total base premium, applying block discounts to components.
export function policyBasePremiums(items: Item[]): { perItemBase: number[]; totalBase: number } {
  // Per-item base premium (without block discount) for use in item-specific surcharges.
  const perItemBase: number[] = items.map((item) => {
    const spec = getItemSpec(item.type);
    if (!spec) throw new Error(`Unknown item type: ${item.type}`);
    return spec.basePremium;
  });

  // Compute total base, applying block discount to components grouped by type.
  let totalBase = 0;
  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    const spec = getItemSpec(item.type);
    if (!spec) throw new Error(`Unknown item type: ${item.type}`);
    if (spec.isComponent) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      totalBase += spec.basePremium;
    }
  }
  for (const type of Object.keys(componentCounts)) {
    const count = componentCounts[type];
    const spec = COMPONENT_ITEMS[type];
    const blocks = Math.floor(count / 3);
    const remainder = count % 3;
    // A block of exactly 3 is 60 G. The block only applies in groups of 3.
    totalBase += blocks * 60 + remainder * spec.basePremium;
  }
  return { perItemBase, totalBase };
}

