22	  // Each policy item can be referenced at most once per claim.
23	  const matched: Item[] = [];
24	  const availableItems = policy.items.slice();
25	  for (const damage of damages) {
26	    if (damage.amount < 0) {
27	      throw new Error(`Negative damage amount: ${damage.amount}`);
