import { Customer, Item } from "./types.js";
import { getItemSpec, isKnownType, policyBasePremiums } from "./items.js";

const PROCESSING_FEE = 5;
const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCH_SURCHARGE_RATE = 0.3;
const LOYALTY_DISCOUNT_RATE = 0.2;
const FIRST_INSURANCE_RATE = 0.1;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;
const HIGH_ENCH_THRESHOLD = 5;
const LOYALTY_THRESHOLD = 2;

export function computePremium(
  customer: Customer,
  items: Item[],
  isFollowUpContract: boolean,
): number {
  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }

  const { perItemBase, totalBase } = policyBasePremiums(items);

  // Item-specific surcharges
  let itemSurcharges = 0;
  for (let i = 0; i < items.length; i++) {
    const item = items[i];
    const base = perItemBase[i];
    if (item.cursed === true) {
      itemSurcharges += base * CURSE_SURCHARGE_RATE;
    }
    if (typeof item.enchantment === "number" && item.enchantment >= HIGH_ENCH_THRESHOLD) {
      itemSurcharges += base * HIGH_ENCH_SURCHARGE_RATE;
    }
  }

  // Policy-wide modifiers, applied to policy base
  let policyModifiers = 0;
  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD) {
    policyModifiers -= totalBase * LOYALTY_DISCOUNT_RATE;
